   199| * Assess a single agent against all 20 capabilities using real code evidence.
   200| * The senior_developer agent has the runtime/brain/tools to actually write code,
   201| * run tests, and commit. Other agents have read-only or analysis-only tools.
   202| */
   203|function assessAgent(agentId: ExecutiveAgentId): CapabilityAssessment[] {
   204|  const def = EXECUTIVE_AGENTS[agentId];
   205|  const execDef = def;
   206|  const entDef = ENTERPRISE_AGENTS[agentId as keyof typeof ENTERPRISE_AGENTS];
   207|  const frameworkAgentId = entDef?.frameworkAgent ?? 'operations';
   208|  const fwDef = AGENTS[frameworkAgentId as keyof typeof AGENTS];
   209|  const tools = fwDef?.allowedTools ?? [];
