   212|  const canTest = tools.includes('run_tests') || tools.includes('lint') || id === 'senior_developer' || id === 'qa';
   213|  const canDeploy = tools.includes('deploy_gate_eval') || tools.includes('rollback_propose') || id === 'deployment';
   214|  const canReadCode = tools.includes('code_read') || id === 'senior_developer' || id === 'cto' || id === 'qa' || id === 'security';
   215|  const hasRuntime = id === 'senior_developer';
   216|
   217|  return CAPABILITY_NAMES.map((cap, idx) => {
   218|    const assessment: CapabilityAssessment = { capability: cap, score: 'FAIL', evidence: '' };
   219|
   220|    switch (idx) {
   221|      case 0: // Reads and understands the existing codebase
   222|        if (canReadCode) {
   223|          assessment.score = 'PASS';
   224|          assessment.evidence = `Agent has code_read tool (${frameworkAgentId}). Engine: ${execDef.engine}`;
   225|        } else if (tools.length > 0) {
