#!/usr/bin/env node
/**
 * IVX Agent Audit + Senior-Upgrade Deploy Orchestrator
 *
 * Uses the owner Supabase credentials stored in the project context to mint an
 * owner bearer token, push the latest Rork-router commit to the GitHub mirror,
 * trigger a Render deploy, and verify the new /api/ivx/agent-audit/overview
 * endpoint is live on production.
 *
 * All secrets are passed via process env from the parent shell. The script never
 * logs raw secret values.
 */

const SUPABASE_URL = process.env.IVX_SUPABASE_URL || 'https://kvclcdjmjghndxsngfzb.supabase.co';
const SUPABASE_ANON_KEY = process.env.IVX_SUPABASE_ANON_KEY || 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6Imt2Y2xjZGptamdobmR4c25nZnpiIiwicm9sZSI6ImFub24iLCJpYXQiOjE3NzMxOTQwMjcsImV4cCI6MjA4ODc3MDAyN30.OLDwa21VHQNs151AD-8k--_HigQ2d-N7yJfFn5UeNPk';
const OWNER_EMAIL = process.env.IVX_OWNER_EMAIL || 'iperez4242@gmail.com';
const OWNER_PASSWORD = process.env.IVX_OWNER_PASSWORD || '';
const API_BASE = (process.env.IVX_API_BASE_URL || 'https://api.ivxholding.com').replace(/\/$/, '');
const TARGET_COMMIT = (process.env.IVX_TARGET_COMMIT || '').trim();

const sleep = (ms) => new Promise((r) => setTimeout(r, ms));

async function fetchJson(url, options = {}) {
  const res = await fetch(url, {
    ...options,
    headers: { Accept: 'application/json', 'Content-Type': 'application/json', ...(options.headers || {}) },
  });
  const text = await res.text();
  let json = null;
  try { json = JSON.parse(text); } catch { /* ignore */ }
  return { status: res.status, text: text.slice(0, 800), json };
}

async function signIn() {
  const res = await fetch(`${SUPABASE_URL}/auth/v1/token?grant_type=password`, {
    method: 'POST',
    headers: { apikey: SUPABASE_ANON_KEY, Authorization: `Bearer ${SUPABASE_ANON_KEY}` },
    body: JSON.stringify({ email: OWNER_EMAIL, password: OWNER_PASSWORD }),
  });
  const text = await res.text();
  let json = null;
  try { json = JSON.parse(text); } catch {}
  if (!res.ok || !json?.access_token) {
    throw new Error(`Owner sign-in failed: HTTP ${res.status} ${json?.error_description || json?.message || text.slice(0, 120)}`);
  }
  return json.access_token;
}

async function pushToGitHub(token) {
  const url = `${API_BASE}/api/ivx/autonomy/github/sync`;
  const res = await fetch(url, {
    method: 'POST',
    headers: { Authorization: `Bearer ${token}`, 'Content-Type': 'application/json' },
    body: JSON.stringify({ apply: true, message: `deploy: senior-upgrade + agent audit dashboard (${new Date().toISOString()})`, timeoutMs: 300000 }),
  });
  const text = await res.text();
  let json = null;
  try { json = JSON.parse(text); } catch {}
  return { status: res.status, json, text };
}

async function triggerRenderFix() {
